css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #020f1a; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; border-bottom: 1px solid rgba(20,184,166,0.15); position: sticky; top: 0; background: rgba(2,15,26,0.9); backdrop-filter: blur(20px); z-index: 100; }
.logo { font-size: 22px; font-weight: 800; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; }
.nav-right { display: flex; gap: 10px; }
.login { padding: 10px 20px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.12); background: transparent; color: white; font-weight: 600; cursor: pointer; }
.list-btn { padding: 10px 20px; border-radius: 10px; border: none; background: #14b8a6; color: white; font-weight: 700; cursor: pointer; }
.hero { min-height: calc(100vh - 72px); display: flex; flex-direction: column; align-items: center; justify-content: center; text-align: center; padding: 60px 72px; position: relative; overflow: hidden; }
.hero-bg { position: absolute; font-size: 400px; opacity: 0.03; pointer-events: none; }
.hero-content { position: relative; z-index: 1; max-width: 800px; }
.hero-tag { display: inline-block; color: #14b8a6; font-size: 14px; font-weight: 700; margin-bottom: 20px; }
h1 { font-size: 96px; font-weight: 900; line-height: 0.95; letter-spacing: -4px; margin-bottom: 20px; }
.hero-content p { color: #6b7280; font-size: 18px; line-height: 1.7; margin-bottom: 36px; }
.search-box { display: flex; gap: 0; background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.1); border-radius: 20px; padding: 12px; max-width: 700px; margin: 0 auto; }
.search-field { flex: 1; padding: 8px 16px; border-right: 1px solid rgba(255,255,255,0.08); } .search-field:last-of-type { border-right: none; }
.search-field label { display: block; font-size: 11px; font-weight: 700; color: #14b8a6; margin-bottom: 4px; letter-spacing: 1px; }
.search-field input, .search-field select { width: 100%; background: transparent; border: none; color: white; font-size: 14px; outline: none; } select option { background: #0a1a2e; }
.search-btn { padding: 14px 24px; border-radius: 14px; border: none; background: linear-gradient(135deg, #14b8a6, #0891b2); color: white; font-weight: 800; font-size: 15px; cursor: pointer; white-space: nowrap; }
.destinations { padding: 80px 72px; }
.destinations h2 { font-size: 42px; font-weight: 800; margin-bottom: 32px; }
.dest-grid { display: grid; grid-template-columns: 1.5fr 1fr 1fr 1fr; gap: 16px; }
.dest-card { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 20px; overflow: hidden; cursor: pointer; transition: all 0.3s; } .dest-card:hover { transform: translateY(-4px); border-color: rgba(20,184,166,0.4); }
.dest-img { display: flex; align-items: center; justify-content: center; font-size: 64px; padding: 32px; } .dest-img.sm { font-size: 40px; padding: 20px; }
.dest-card.big .dest-img { font-size: 80px; padding: 40px; }
.dest-info { padding: 14px 16px; border-top: 1px solid rgba(255,255,255,0.06); } .dest-info strong { display: block; font-size: 16px; font-weight: 700; } .dest-info span { color: #6b7280; font-size: 12px; }
.dest-price { color: #14b8a6; font-size: 13px; font-weight: 700; margin-top: 4px; }
.why { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.07); } .why h2 { font-size: 42px; font-weight: 800; margin-bottom: 36px; }
.why-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 20px; }
.why-card { padding: 28px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); }
.why-icon { font-size: 32px; margin-bottom: 14px; } .why-card h3 { font-size: 16px; font-weight: 700; margin-bottom: 8px; } .why-card p { color: #6b7280; font-size: 14px; line-height: 1.6; }
